import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

public class LoggingDemo {

    // ── One logger per class — enables per-package level control ──────
    private static final Logger log = LoggerFactory.getLogger(LoggingDemo.class);

    // ── Log level demonstration ───────────────────────────────────────
    static void demonstrateLevels() {
        log.trace("TRACE: entering demonstrateLevels() — usually disabled in production");
        log.debug("DEBUG: internal values, request params — disable in production");
        log.info("INFO: user login, order created, service started — always on");
        log.warn("WARN: slow query ({}ms), deprecated method called", 1500);
        log.error("ERROR: unhandled exception, payment failed, DB unreachable");
    }

    // ── {} placeholders vs string concatenation ───────────────────────
    static void demonstratePlaceholders(String userId, double amount) {
        // BAD: concatenation runs even when DEBUG is OFF
        // log.debug("Processing payment for user " + userId + " amount " + amount);

        // GOOD: {} deferred — only formats if DEBUG is enabled
        log.debug("Processing payment for user {} amount {}", userId, amount);

        // Exception logging — always pass exception as LAST argument
        try {
            throw new RuntimeException("Payment gateway timeout");
        } catch (Exception e) {
            // WRONG: log.error(e.getMessage());  — no stack trace!
            // RIGHT: exception as final arg → prints full stack trace
            log.error("Payment failed for user {} — {}", userId, e.getMessage(), e);
        }

        // Conditional log (for expensive toString operations)
        if (log.isDebugEnabled()) {
            log.debug("Full object: {}", expensiveToString());
        }
    }

    static String expensiveToString() { return "huge-object-state"; }

    // ── MDC — Mapped Diagnostic Context ──────────────────────────────
    // MDC attaches key-value pairs to every log line from this thread
    // Pattern: %X{requestId} %X{userId} in logback pattern includes MDC values
    static void simulateRequest(String requestId, String userId) {
        try {
            MDC.put("requestId", requestId);
            MDC.put("userId",    userId);

            log.info("Request started");         // prints with requestId+userId in pattern
            processOrder();
            log.info("Request completed");
        } finally {
            MDC.clear();  // CRITICAL: ThreadLocal must be cleared for thread reuse
        }
    }

    static void processOrder() {
        // MDC values automatically appear in ALL log lines from this thread
        log.debug("Validating order items");
        log.info("Order validated, proceeding to payment");
        log.debug("Calling payment gateway");
    }

    public static void main(String[] args) {
        System.out.println("--- Log Level Demo ---");
        demonstrateLevels();

        System.out.println();
        System.out.println("--- Placeholder Demo ---");
        demonstratePlaceholders("user-42", 99.99);

        System.out.println();
        System.out.println("--- MDC Demo ---");
        // Simulate two concurrent requests (in real app: different threads)
        simulateRequest("req-abc123", "user-42");
        simulateRequest("req-xyz789", "user-17");

        System.out.println();
        System.out.println("Pattern example in logback.xml:");
        System.out.println("%d{yyyy-MM-dd HH:mm:ss.SSS} [%thread] %-5level"
            + " %logger{36} [%X{requestId}] [%X{userId}] - %msg%n");
        System.out.println("Output: 2026-04-15 10:23:45.123 [http-nio-8080-3] INFO"
            + "  c.l.service.OrderService [req-abc123] [user-42] - Order validated");
    }
}

/**
 * Logback configuration examples and async logging impact.
 * (logback-spring.xml content shown as comments + Java performance demo)
 */

/*
 === logback-spring.xml (Spring Boot reads this automatically) ===

<?xml version="1.0" encoding="UTF-8"?>
<configuration>

  <!-- Spring Boot includes: colored console, sensible defaults -->
  <include resource="org/springframework/boot/logging/logback/defaults.xml"/>

  <!-- Console appender (dev/local) -->
  <appender name="CONSOLE" class="ch.qos.logback.core.ConsoleAppender">
    <encoder>
      <pattern>%d{HH:mm:ss.SSS} [%thread] %-5level %logger{36} [%X{reqId}] - %msg%n</pattern>
    </encoder>
  </appender>

  <!-- Rolling file appender: 10MB files, keep 30 days -->
  <appender name="FILE" class="ch.qos.logback.core.rolling.RollingFileAppender">
    <file>logs/app.log</file>
    <rollingPolicy class="ch.qos.logback.core.rolling.SizeAndTimeBasedRollingPolicy">
      <fileNamePattern>logs/app-%d{yyyy-MM-dd}.%i.log.gz</fileNamePattern>
      <maxFileSize>10MB</maxFileSize>     <!-- rotate when file hits 10MB -->
      <maxHistory>30</maxHistory>         <!-- keep 30 days of history -->
      <totalSizeCap>1GB</totalSizeCap>   <!-- never exceed 1GB total -->
    </rollingPolicy>
    <encoder>
      <!-- JSON format for ELK/Splunk ingestion (logstash-logback-encoder) -->
      <!-- <encoder class="net.logstash.logback.encoder.LogstashEncoder"/> -->
      <pattern>%d{ISO8601} [%thread] %-5level %logger{36} [%X{reqId}] - %msg%n</pattern>
    </encoder>
  </appender>

  <!-- Async wrapper: moves I/O off application thread -->
  <appender name="ASYNC_FILE" class="ch.qos.logback.classic.AsyncAppender">
    <appender-ref ref="FILE"/>
    <queueSize>1024</queueSize>          <!-- buffer 1024 log events -->
    <discardingThreshold>0</discardingThreshold>  <!-- 0 = never discard (default discards TRACE/DEBUG) -->
    <includeCallerData>false</includeCallerData>   <!-- caller lookup is expensive -->
  </appender>

  <!-- ERROR-only log file for alerting -->
  <appender name="ERROR_FILE" class="ch.qos.logback.core.rolling.RollingFileAppender">
    <filter class="ch.qos.logback.classic.filter.LevelFilter">
      <level>ERROR</level>
      <onMatch>ACCEPT</onMatch>
      <onMismatch>DENY</onMismatch>
    </filter>
    <file>logs/error.log</file>
    <rollingPolicy class="ch.qos.logback.core.rolling.TimeBasedRollingPolicy">
      <fileNamePattern>logs/error-%d{yyyy-MM-dd}.log.gz</fileNamePattern>
      <maxHistory>90</maxHistory>  <!-- keep errors longer -->
    </rollingPolicy>
    <encoder>
      <pattern>%d{ISO8601} [%thread] ERROR %logger{36} [%X{reqId}] - %msg%n</pattern>
    </encoder>
  </appender>

  <!-- Per-environment config using Spring profiles -->
  <springProfile name="local,dev">
    <root level="DEBUG">
      <appender-ref ref="CONSOLE"/>
    </root>
    <logger name="com.myapp" level="DEBUG" additivity="false">
      <appender-ref ref="CONSOLE"/>
    </logger>
    <logger name="org.hibernate.SQL" level="DEBUG"/> <!-- show SQL in dev -->
    <logger name="org.hibernate.type" level="TRACE"/> <!-- show SQL params -->
  </springProfile>

  <springProfile name="prod">
    <root level="INFO">
      <appender-ref ref="ASYNC_FILE"/>
      <appender-ref ref="ERROR_FILE"/>
    </root>
    <logger name="com.myapp" level="INFO" additivity="false">
      <appender-ref ref="ASYNC_FILE"/>
      <appender-ref ref="ERROR_FILE"/>
    </logger>
  </springProfile>

</configuration>
*/

public class LoggingConfigDemo {
    public static void main(String[] args) {
        System.out.println("Logback key concepts:");
        System.out.println();
        System.out.println("Appender types:");
        System.out.println("  ConsoleAppender     — stdout, development");
        System.out.println("  FileAppender        — single file, simple");
        System.out.println("  RollingFileAppender — rotate by size/date, production");
        System.out.println("  AsyncAppender       — non-blocking wrapper, production");
        System.out.println();
        System.out.println("AsyncAppender behavior:");
        System.out.println("  queueSize=1024 — if queue fills, app thread blocks");
        System.out.println("  discardingThreshold=0 — never drop logs (safer)");
        System.out.println("  discardingThreshold=20 — drop TRACE/DEBUG when 80% full");
        System.out.println();
        System.out.println("additivity=false — logger does NOT send to parent (root)");
        System.out.println("additivity=true  — logger AND root both receive the event");
        System.out.println("=> Use additivity=false to avoid duplicate log lines");
        System.out.println();
        System.out.println("Spring Boot application.properties shortcuts:");
        System.out.println("  logging.level.root=INFO");
        System.out.println("  logging.level.com.myapp=DEBUG");
        System.out.println("  logging.file.name=logs/app.log");
        System.out.println("  logging.pattern.console=%d{HH:mm:ss} %-5level - %msg%n");
        System.out.println();
        System.out.println("Log4j2 async (faster than Logback async):");
        System.out.println("  <AsyncLogger name='com.myapp' level='INFO'>");
        System.out.println("  Uses LMAX Disruptor ring buffer — near-zero GC pressure");
        System.out.println("  Include: log4j2 + disruptor dependency");
        System.out.println("  Spring Boot: exclude logback, add log4j2 starter");
    }
}

