import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import java.util.List;

public class Q1 {
    private static final Logger log = LoggerFactory.getLogger(Q1.class);

    // Bug 1: string concatenation
    static void processUser(String userId, String email) {
        log.debug("Processing user: " + userId + " email: " + email); // BUG
    }

    // Bug 2: exception without stack trace
    static void callApi(String url) {
        try {
            throw new RuntimeException("Timeout after 5s");
        } catch (Exception e) {
            log.error("API call failed: " + e.getMessage()); // BUG
        }
    }

    // Bug 3: MDC without clear
    static void handleRequest(String requestId) {
        MDC.put("reqId", requestId);
        log.info("Request started");
        // ... processing ...
        // BUG: no MDC.clear()
    }

    // Bug 4: wrong level (expected event treated as warning)
    static void userLoggedOut(String userId) {
        log.warn("User {} logged out", userId); // BUG: this is normal
    }

    // Bug 5: logging in tight loop
    static void processItems(List<String> items) {
        for (String item : items) {
            log.info("Processing item: {}", item); // BUG for n=10000
        }
    }

    public static void main(String[] args) {
        System.out.println("Identify the 5 logging bugs and their fixes:");
    }
}

