import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import java.util.List;

public class Q1 {
    private static final Logger log = LoggerFactory.getLogger(Q1.class);

    // Fix 1: {} placeholder — formatting skipped if DEBUG is off
    static void processUser(String userId, String email) {
        log.debug("Processing user: {} email: {}", userId, email);
        //        ^ placeholder      ^ placeholder — no string concat
    }

    // Fix 2: exception as last argument — includes full stack trace
    static void callApi(String url) {
        try {
            throw new RuntimeException("Timeout after 5s");
        } catch (Exception e) {
            log.error("API call failed for URL {}", url, e); // e as last arg!
        }
    }

    // Fix 3: MDC.clear() in finally — always runs even on exception
    static void handleRequest(String requestId) {
        try {
            MDC.put("reqId", requestId);
            log.info("Request started");
            // ... processing ...
        } finally {
            MDC.clear(); // mandatory — threads are reused in thread pools!
        }
    }

    // Fix 4: INFO for expected business events (logout is normal)
    static void userLoggedOut(String userId) {
        log.info("User {} logged out", userId);
        // WARN is for unexpected/concerning events, not routine operations
        // Reserve WARN for: slow queries, deprecated usage, retries, near-limits
    }

    // Fix 5: aggregate first, log summary
    static void processItems(List<String> items) {
        log.info("Starting batch: {} items", items.size()); // one line
        int errors = 0;
        for (String item : items) {
            try {
                // process item
            } catch (Exception e) {
                errors++;
                log.debug("Failed item: {}", item, e); // only if DEBUG enabled
            }
        }
        log.info("Batch complete: {} processed, {} errors", items.size(), errors);
        // Result: 2 log lines instead of 10,000
    }

    public static void main(String[] args) {
        System.out.println("The 5 logging anti-patterns:");
        System.out.println("1. String concat → {} placeholders (avoids cost when level off)");
        System.out.println("2. e.getMessage() → pass e as final arg (gets stack trace)");
        System.out.println("3. No MDC.clear() → always clear in finally (thread reuse)");
        System.out.println("4. WARN for normal → INFO for expected events");
        System.out.println("5. Log per item → log aggregate summary");
    }
}

