import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import java.io.IOException;
import java.util.UUID;

public class Q2 {

    static class RequestMDCFilter implements Filter {
        private static final String REQUEST_ID_HEADER = "X-Request-ID";
        private static final Logger log = LoggerFactory.getLogger(RequestMDCFilter.class);

        @Override
        public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain)
                throws IOException, ServletException {

            HttpServletRequest httpReq = (HttpServletRequest) req;

            // 1. Use caller's requestId for distributed tracing, or generate new one
            String requestId = httpReq.getHeader(REQUEST_ID_HEADER);
            if (requestId == null || requestId.isBlank()) {
                requestId = UUID.randomUUID().toString().substring(0, 8); // short form
            }

            // 2. Get authenticated user from session
            HttpSession session = httpReq.getSession(false);
            String user = (session != null && session.getAttribute("user") != null)
                ? (String) session.getAttribute("user")
                : "anonymous";

            try {
                // 3. Populate MDC — every log line from this thread will include these
                MDC.put("requestId", requestId);
                MDC.put("user",      user);
                MDC.put("method",    httpReq.getMethod());
                MDC.put("path",      httpReq.getRequestURI());

                log.info("Request started");

                // 4. Also echo the requestId back in response (for client correlation)
                ((HttpServletResponse) res).setHeader(REQUEST_ID_HEADER, requestId);

                chain.doFilter(req, res);

                log.info("Request completed — status: {}",
                    ((HttpServletResponse) res).getStatus());

            } finally {
                // 5. ALWAYS clear — thread goes back to pool and serves next request
                MDC.clear();
            }
        }
    }

    static class OrderService {
        private static final Logger log = LoggerFactory.getLogger(OrderService.class);

        void createOrder(String productId, int qty) {
            // requestId and user automatically appear in EVERY log line
            // because MDC is populated by the filter for this thread
            log.debug("Validating stock for product {} qty {}", productId, qty);
            log.info("Creating order: product={} qty={}", productId, qty);
            // In logback pattern %X{requestId} -> req-abc123
            // Output: 2026-04-15 10:23:45 [http-9] INFO OrderService [req-abc123] [alice] - Creating order
        }
    }

    public static void main(String[] args) {
        System.out.println("RequestMDCFilter behaviour:");
        System.out.println("1. Reads X-Request-ID header (for distributed trace)");
        System.out.println("2. Falls back to short UUID if header missing");
        System.out.println("3. Reads user from session (or 'anonymous')");
        System.out.println("4. MDC.put() fills %X{requestId} and %X{user} in log pattern");
        System.out.println("5. MDC.clear() in finally — thread-pool safety");
        System.out.println();
        System.out.println("logback pattern with MDC:");
        System.out.println("%d{HH:mm:ss} [%thread] %-5level %logger{36} [%X{requestId}] [%X{user}] - %msg%n");
        System.out.println();
        System.out.println("Result: every log line across all services shows requestId");
        System.out.println("grep 'req-abc123' *.log → full request trace across all classes");
    }
}
